// ─── DIAGRAMS (inline SVG components) ────────────────────────
function MalaGripDiagram() {
  return (
    <svg viewBox="0 0 520 160" style={{ width: "100%", maxWidth: 520, display: "block", margin: "16px auto" }}>
      <g transform="translate(20,10)">
        <text x="100" y="14" fill="#c9a84c" fontFamily="'IBM Plex Mono', monospace" fontSize="9" letterSpacing="1.5" textAnchor="middle">HINDU GRIP</text>
        <ellipse cx="100" cy="80" rx="60" ry="50" fill="none" stroke="#2a2a33" strokeWidth="1.5" />
        <circle cx="100" cy="36" r="6" fill="#c9a84c" opacity="0.8" />
        <text x="100" y="39" fill="#0a0a0c" fontFamily="'IBM Plex Mono'" fontSize="7" textAnchor="middle">G</text>
        {Array.from({length: 16}).map((_, i) => {
          const a = (i / 16) * Math.PI * 2 - Math.PI/2 + 0.2;
          return <circle key={i} cx={100 + Math.cos(a)*52} cy={80 + Math.sin(a)*42} r="3" fill="#7a7a85" opacity="0.5" />;
        })}
        <text x="100" y="130" fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="10" textAnchor="middle">Right hand always</text>
        <text x="100" y="145" fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="10" textAnchor="middle">Ring finger · Middle finger pulls</text>
      </g>
      <g transform="translate(280,10)">
        <text x="100" y="14" fill="#7B9EA8" fontFamily="'IBM Plex Mono', monospace" fontSize="9" letterSpacing="1.5" textAnchor="middle">BUDDHIST GRIP</text>
        <ellipse cx="100" cy="80" rx="60" ry="50" fill="none" stroke="#2a2a33" strokeWidth="1.5" />
        <circle cx="100" cy="36" r="6" fill="#7B9EA8" opacity="0.8" />
        <text x="100" y="39" fill="#0a0a0c" fontFamily="'IBM Plex Mono'" fontSize="7" textAnchor="middle">G</text>
        {Array.from({length: 16}).map((_, i) => {
          const a = (i / 16) * Math.PI * 2 - Math.PI/2 + 0.2;
          return <circle key={i} cx={100 + Math.cos(a)*52} cy={80 + Math.sin(a)*42} r="3" fill="#7a7a85" opacity="0.5" />;
        })}
        <text x="100" y="130" fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="10" textAnchor="middle">Left or right hand</text>
        <text x="100" y="145" fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="10" textAnchor="middle">Middle or ring finger · Thumb pulls</text>
      </g>
    </svg>
  );
}

