function ChakraDiagram() {
  const chakras = [
    { y: 18, label: "Ajna", bija: "OM", color: "#e8e6e3", el: "\u2014" },
    { y: 48, label: "Vishuddha", bija: "HUM", color: "#457B9D", el: "Space" },
    { y: 78, label: "Anahata", bija: "YUM", color: "#2D6A4F", el: "Air" },
    { y: 108, label: "Manipura", bija: "RUM", color: "#9B2226", el: "Fire" },
    { y: 138, label: "Svadhisthana", bija: "VUM", color: "#e8e6e3", el: "Water" },
    { y: 168, label: "Muladhara", bija: "LUM", color: "#c9a84c", el: "Earth" },
  ];
  return (
    <svg viewBox="0 0 380 195" style={{ width: "100%", maxWidth: 380, display: "block", margin: "16px auto" }}>
      <line x1="50" y1="12" x2="50" y2="182" stroke="#2a2a33" strokeWidth="2" />
      {chakras.map((c, i) => (
        <g key={i}>
          <circle cx="50" cy={c.y} r="8" fill="none" stroke={c.color} strokeWidth="1.5" />
          <circle cx="50" cy={c.y} r="3" fill={c.color} opacity="0.6" />
          <text x="72" y={c.y + 4} fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="12" fontWeight="500">{c.label}</text>
          <text x="185" y={c.y + 4} fill={c.color} fontFamily="'IBM Plex Mono'" fontSize="12" fontWeight="500">{c.bija}</text>
          <text x="240" y={c.y + 4} fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="11">{c.el}</text>
        </g>
      ))}
      <text x="72" y="192" fill="#7a7a85" fontFamily="'IBM Plex Mono'" fontSize="8" letterSpacing="1">LOCATION</text>
      <text x="185" y="192" fill="#7a7a85" fontFamily="'IBM Plex Mono'" fontSize="8" letterSpacing="1">BIJA</text>
      <text x="240" y="192" fill="#7a7a85" fontFamily="'IBM Plex Mono'" fontSize="8" letterSpacing="1">ELEMENT</text>
    </svg>
  );
}

function KapalabhatiDiagram() {
  const steps = [
    { n: "1", label: "Bhastrika", sub: "30\u2013100 rounds" },
    { n: "2", label: "Full exhale", sub: "Empty completely" },
    { n: "3", label: "Full inhale", sub: "Three-part breath" },
    { n: "4", label: "Hold", sub: "7\u201312 seconds" },
    { n: "5", label: "Left exhale", sub: "Close right nostril" },
  ];
  return (
    <svg viewBox="0 0 490 56" style={{ width: "100%", maxWidth: 490, display: "block", margin: "16px auto" }}>
      <defs>
        <marker id="ka" markerWidth="5" markerHeight="5" refX="4" refY="2.5" orient="auto"><path d="M0,0 L5,2.5 L0,5" fill="#7a7a85" /></marker>
      </defs>
      {steps.map((s, i) => (
        <g key={i} transform={`translate(${i * 98}, 0)`}>
          <rect x="2" y="2" width="82" height="50" rx="4" fill="#1c1c22" stroke="#2a2a33" strokeWidth="1" />
          <text x="12" y="18" fill="#c9a84c" fontFamily="'IBM Plex Mono'" fontSize="9">{s.n}</text>
          <text x="24" y="18" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11" fontWeight="500">{s.label}</text>
          <text x="12" y="36" fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="9">{s.sub}</text>
          {i < 4 && <line x1="86" y1="27" x2="98" y2="27" stroke="#7a7a85" strokeWidth="1" markerEnd="url(#ka)" />}
        </g>
      ))}
    </svg>
  );
}

