function NadiShodhanaCycleDiagram() {
  return (
    <svg viewBox="0 0 460 200" style={{ width: "100%", maxWidth: 460, display: "block", margin: "16px auto" }}>
      <defs>
        <marker id="up" markerWidth="6" markerHeight="6" refX="3" refY="0" orient="auto"><path d="M0,6 L3,0 L6,6" fill="#c9a84c" /></marker>
        <marker id="dn" markerWidth="6" markerHeight="6" refX="3" refY="6" orient="auto"><path d="M0,0 L3,6 L6,0" fill="#7B9EA8" /></marker>
      </defs>
      <text x="40" y="14" fill="#c9a84c" fontFamily="'IBM Plex Mono'" fontSize="9" letterSpacing="1.5">ASCEND</text>
      {["LUM","VUM","RUM","YUM","HUM","OM"].map((b, i) => (
        <g key={i}>
          <rect x="30" y={24 + i*28} width="60" height="22" rx="3" fill="#1c1c22" stroke="#2a2a33" strokeWidth="1" />
          <text x="60" y={38 + i*28} fill="#c9a84c" fontFamily="'IBM Plex Mono'" fontSize="10" textAnchor="middle">{b}</text>
          {i < 5 && <line x1="60" y1={47 + i*28} x2="60" y2={51 + i*28} stroke="#c9a84c" strokeWidth="1" markerEnd="url(#up)" />}
        </g>
      ))}
      <text x="96" y={38 + 5*28} fill="#7a7a85" fontFamily="'IBM Plex Sans'" fontSize="9">{"\u00d7"}2</text>
      <text x="180" y="14" fill="#7B9EA8" fontFamily="'IBM Plex Mono'" fontSize="9" letterSpacing="1.5">DESCEND</text>
      {["OM","HUM","YUM","RUM","VUM","LUM"].map((b, i) => (
        <g key={i}>
          <rect x="170" y={24 + i*28} width="60" height="22" rx="3" fill="#1c1c22" stroke="#2a2a33" strokeWidth="1" />
          <text x="200" y={38 + i*28} fill="#7B9EA8" fontFamily="'IBM Plex Mono'" fontSize="10" textAnchor="middle">{b}</text>
          {i < 5 && <line x1="200" y1={47 + i*28} x2="200" y2={51 + i*28} stroke="#7B9EA8" strokeWidth="1" markerEnd="url(#dn)" />}
        </g>
      ))}
      <g transform="translate(260, 24)">
        <text x="0" y="10" fill="#7a7a85" fontFamily="'IBM Plex Mono'" fontSize="9" letterSpacing="1">AT EACH CHAKRA</text>
        <text x="0" y="32" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11">Feel the center</text>
        <text x="0" y="50" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11">Bija as counter</text>
        <text x="0" y="68" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11">Nadi Shodhana (1 round)</text>
        <text x="0" y="86" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11">Kumbhaka (your ratio)</text>
        <text x="0" y="104" fill="#e8e6e3" fontFamily="'IBM Plex Sans'" fontSize="11">Bandhas (if ready)</text>
      </g>
    </svg>
  );
}

